 1	import * as React from 'react';
 2	import { IstioConfigItem } from './IstioConfigPreview';
 3	import { Tab, Tabs } from '@patternfly/react-core';
 4	import { EditorPreview, PolicyItem } from './EditorPreview';
 5	import { yamlDumpOptions } from '../../types/IstioConfigDetails';
 6	import { isEqual } from 'lodash-es';
 7	import { dump } from 'js-yaml';
 8	
 9	interface Props {
10	  isIstioNew?: boolean;
11	  items: IstioConfigItem[];
12	  onChange: (obj: PolicyItem, index: number) => void;
13	  orig: IstioConfigItem[];
14	}
15	
16	export const EditResources: React.FC<Props> = (props: Props) => {
17	  const [resourceTab, setResourceTab] = React.useState<number>(0);
18	
19	  return (
20	    <Tabs activeKey={resourceTab} onSelect={(_, tab) => setResourceTab(Number(tab))}>
21	      {props.items
22	        .sort((a, b) =>
23	          props.isIstioNew
24	            ? a.metadata.namespace!.localeCompare(b.metadata.namespace!)
25	            : a.metadata.name.localeCompare(b.metadata.name)
26	        )
27	        .map((item, i) => {
28	          return (
29	            <Tab
30	              eventKey={i}
31	              key={i}
32	              title={
33	                <>
34	                  {props.isIstioNew ? item.metadata.namespace : item.metadata.name}{' '}
35	                  {!isEqual(
36	                    item,
37	                    props.orig.filter(it =>
38	                      props.isIstioNew
39	                        ? it.metadata.namespace === item.metadata.namespace
40	                        : it.metadata.name === item.metadata.name
41	                    )[0]
42	                  ) && '*'}
43	                </>
44	              }
45	            >
46	              <EditorPreview yaml={dump(item, yamlDumpOptions)} onChange={obj => props.onChange(obj, i)} />
47	            </Tab>
48	          );
49	        })}
50	    </Tabs>
51	  );
52	};

